def _ident(name: str) -> str:
    text = str(name or "")
    if not text.replace("_", "a").isalnum() or not (text[0].isalpha() or text[0] == "_"):
        raise ValueError(f"invalid identifier: {text}")
    return text


def _create_table_sql(name: str, body: str) -> str:
    return f"CREATE TABLE IF NOT EXISTS {_ident(name)} ({body})"


def up(conn) -> None:
    schema = quote_ident(schema_name())
    conn.execute(f"CREATE SCHEMA IF NOT EXISTS {schema}")
    conn.execute(f"SET search_path = {schema}, public")
    for table_name, body in TABLE_DEFS:
        conn.execute(_create_table_sql(table_name, body))
    for statement in INDEX_DEFS:
        conn.execute(statement)
